func (fx *FreightServiceSiteTestSuiteConfig) testBatchGet(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if provided parent is invalid.
	t.Run("invalid parent", func(t *testing.T) {
		fx.maybeSkip(t)
		req := &BatchGetSitesRequest{}
		req.SetParent("invalid resource name")
		req.SetNames([]string{})
		_, err := fx.Service().BatchGetSites(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument if no names are provided.
	t.Run("names missing", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		req := &BatchGetSitesRequest{}
		req.SetParent(parent)
		req.SetNames([]string{})
		_, err := fx.Service().BatchGetSites(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument if a provided name is not valid.
	t.Run("invalid names", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		req := &BatchGetSitesRequest{}
		req.SetParent(parent)
		req.SetNames([]string{
			"invalid resource name",
		})
		_, err := fx.Service().BatchGetSites(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument if a provided name only contains wildcards (-)
	t.Run("wildcard name", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		req := &BatchGetSitesRequest{}
		req.SetParent(parent)
		req.SetNames([]string{
			"shippers/-/sites/-",
		})
		_, err := fx.Service().BatchGetSites(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	{
		parent := fx.nextParent(t, false)
		created00 := fx.create(t, parent)
		created01 := fx.create(t, parent)
		created02 := fx.create(t, parent)
		// Resources should be returned without errors if they exist.
		t.Run("all exists", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &BatchGetSitesRequest{}
			req.SetParent(parent)
			req.SetNames([]string{
				created00.GetName(),
				created01.GetName(),
				created02.GetName(),
			})
			response, err := fx.Service().BatchGetSites(fx.Context(), req)
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				[]*Site{
					created00,
					created01,
					created02,
				},
				response.GetSites(),
				protocmp.Transform(),
			)
		})

		// The method must be atomic; it must fail for all resources
		// or succeed for all resources (no partial success).
		t.Run("atomic", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &BatchGetSitesRequest{}
			req.SetParent(parent)
			req.SetNames([]string{
				created00.GetName(),
				created01.GetName() + "notfound",
				created02.GetName(),
			})
			_, err := fx.Service().BatchGetSites(fx.Context(), req)
			assert.Equal(t, codes.NotFound, status.Code(err), err)
		})

		// If a caller sets the "parent", and the parent collection in the name of any resource
		// being retrieved does not match, the request must fail.
		t.Run("parent mismatch", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &BatchGetSitesRequest{}
			req.SetParent(fx.peekNextParent(t))
			req.SetNames([]string{
				created00.GetName(),
			})
			_, err := fx.Service().BatchGetSites(fx.Context(), req)
			assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
		})

		// The order of resources in the response must be the same as the names in the request.
		t.Run("ordered", func(t *testing.T) {
			fx.maybeSkip(t)
			for _, order := range [][]*Site{
				{created00, created01, created02},
				{created01, created00, created02},
				{created02, created01, created00},
			} {
				req := &BatchGetSitesRequest{}
				req.SetParent(parent)
				req.SetNames([]string{
					order[0].GetName(),
					order[1].GetName(),
					order[2].GetName(),
				})
				response, err := fx.Service().BatchGetSites(fx.Context(), req)
				assert.NilError(t, err)
				assert.DeepEqual(t, order, response.GetSites(), protocmp.Transform())
			}
		})

		// If a caller provides duplicate names, the service should return
		// duplicate resources.
		t.Run("duplicate names", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &BatchGetSitesRequest{}
			req.SetParent(parent)
			req.SetNames([]string{
				created00.GetName(),
				created00.GetName(),
			})
			response, err := fx.Service().BatchGetSites(fx.Context(), req)
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				[]*Site{
					created00,
					created00,
				},
				response.GetSites(),
				protocmp.Transform(),
			)
		})

	}
}

